import React from 'react';
import { Box, Typography, Avatar, Paper, Button, Divider, Grid, Card, CardContent, LinearProgress, Tabs, Tab, CircularProgress } from '@mui/material';
import { styled } from '@mui/material/styles';
import { Edit, CardGiftcard, History, Person } from '@mui/icons-material';
import { motion } from 'framer-motion';
import { useUser } from '../context/UserContext';

const ProfileHeader = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(3),
  borderRadius: theme.spacing(2),
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  textAlign: 'center',
  boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
  marginBottom: theme.spacing(3),
  background: 'linear-gradient(135deg, #ffffff 0%, #f7f9fc 100%)',
}));

const StyledAvatar = styled(Avatar)(({ theme }) => ({
  width: 120,
  height: 120,
  border: `4px solid ${theme.palette.primary.main}`,
  boxShadow: '0 4px 14px rgba(33, 150, 243, 0.3)',
  marginBottom: theme.spacing(2),
}));

const StatsCard = styled(Card)(({ theme }) => ({
  borderRadius: theme.spacing(2),
  boxShadow: '0 4px 14px rgba(0,0,0,0.08)',
  height: '100%',
  transition: 'transform 0.2s ease',
  '&:hover': {
    transform: 'translateY(-5px)',
  },
}));

const SectionTitle = styled(Typography)(({ theme }) => ({
  fontWeight: 600,
  marginBottom: theme.spacing(2),
  position: 'relative',
  '&:after': {
    content: '""',
    position: 'absolute',
    left: 0,
    bottom: -8,
    width: 40,
    height: 3,
    backgroundColor: theme.palette.primary.main,
    borderRadius: 3,
  },
}));

const TabPanel = (props: { children?: React.ReactNode; index: number; value: number }) => {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`simple-tabpanel-${index}`}
      aria-labelledby={`simple-tab-${index}`}
      style={{ padding: '16px 0' }}
      {...other}
    >
      {value === index && children}
    </div>
  );
};

const ProfilePage: React.FC = () => {
  const { user, profile, loading, error, refreshProfile } = useUser();
  const [tabValue, setTabValue] = React.useState(0);

  const handleTabChange = (_event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };

  if (loading) {
    return <Box sx={{ display: 'flex', justifyContent: 'center', py: 10 }}><CircularProgress /></Box>;
  }
  if (error) {
    return <Box sx={{ textAlign: 'center', py: 5 }}><Typography color="error">{error}</Typography></Box>;
  }
  if (!profile) {
    return <Box sx={{ textAlign: 'center', py: 5 }}><Typography>Профиль не найден</Typography></Box>;
  }

  return (
    <Box sx={{ padding: 2, paddingBottom: 10, marginTop: 2 }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
      >
        <ProfileHeader elevation={0}>
          <StyledAvatar src={profile.photoURL} alt={profile.displayName || 'Пользователь'} />
          <Typography variant="h5" sx={{ fontWeight: 600, mb: 1 }}>
            {profile.displayName || 'Пользователь'}
          </Typography>
          {profile.username && (
            <Typography variant="body2" color="text.secondary">@{profile.username}</Typography>
          )}
          {profile.telegramId && (
            <Typography variant="body2" color="text.secondary">Telegram ID: {profile.telegramId}</Typography>
          )}
          <Button 
            variant="outlined" 
            size="small"
            startIcon={<Edit />}
            sx={{ borderRadius: 20, mb: 2 }}
          >
            Редактировать
          </Button>
          
          <Grid container spacing={3} sx={{ mt: 1 }}>
            <Grid size={{ xs: 4 }}>
              <Box>
                <Typography variant="h6" sx={{ fontWeight: 700, color: 'primary.main' }}>{profile.ticketsTotal ?? 0}</Typography>
                <Typography variant="body2" color="text.secondary">Билетов</Typography>
              </Box>
            </Grid>
            <Grid size={{ xs: 4 }}>
              <Box>
                <Typography variant="h6" sx={{ fontWeight: 700, color: 'primary.main' }}>{profile.wins ?? 0}</Typography>
                <Typography variant="body2" color="text.secondary">Побед</Typography>
              </Box>
            </Grid>
            <Grid size={{ xs: 4 }}>
              <Box>
                <Typography variant="h6" sx={{ fontWeight: 700, color: 'primary.main' }}>{profile.balance ?? 0} ₽</Typography>
                <Typography variant="body2" color="text.secondary">Баланс</Typography>
              </Box>
            </Grid>
          </Grid>
        </ProfileHeader>
        
        <Box sx={{ mb: 4 }}>
          <Tabs 
            value={tabValue} 
            onChange={handleTabChange}
            variant="fullWidth"
            sx={{
              '& .MuiTabs-indicator': {
                height: 3,
                borderRadius: 3,
              },
              '& .MuiTab-root': {
                textTransform: 'none',
                fontWeight: 600,
                fontSize: '0.9rem',
              },
              mb: 2
            }}
          >
            <Tab icon={<CardGiftcard />} label="Активные билеты" />
            <Tab icon={<History />} label="История" />
            <Tab icon={<Person />} label="Личные данные" />
          </Tabs>
          
          <TabPanel value={tabValue} index={0}>
            <Grid container spacing={2}>
              {(profile.activeTickets ?? []).map((ticket: any) => (
                <Grid size={{ xs: 12 }} key={ticket.id}>
                  <motion.div
                    initial={{ opacity: 0, x: -10 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ duration: 0.3 }}
                  >
                    <StatsCard>
                      <CardContent>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                          <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
                            {ticket.car}
                          </Typography>
                          <Typography variant="body2" color="primary" sx={{ fontWeight: 600 }}>
                            Билет {ticket.ticketNumber}
                          </Typography>
                        </Box>
                        <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                          Розыгрыш: {ticket.drawDate}
                        </Typography>
                        <Box sx={{ width: '100%', mb: 1 }}>
                          <LinearProgress 
                            variant="determinate" 
                            value={ticket.progress} 
                            sx={{ 
                              height: 6, 
                              borderRadius: 5,
                              backgroundColor: 'rgba(33, 150, 243, 0.2)',
                              '& .MuiLinearProgress-bar': {
                                borderRadius: 5,
                                background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
                              }
                            }}
                          />
                        </Box>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <Typography variant="caption" color="text.secondary">
                            Заполнено {ticket.progress}%
                          </Typography>
                          <Button size="small" color="primary" sx={{ borderRadius: 20, textTransform: 'none' }}>
                            Подробнее
                          </Button>
                        </Box>
                      </CardContent>
                    </StatsCard>
                  </motion.div>
                </Grid>
              ))}
            </Grid>
          </TabPanel>
          
          <TabPanel value={tabValue} index={1}>
            <Grid container spacing={2}>
              {(profile.historyTickets ?? []).map((ticket: any) => (
                <Grid size={{ xs: 12 }} key={ticket.id}>
                  <motion.div
                    initial={{ opacity: 0, x: -10 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ duration: 0.3 }}
                  >
                    <StatsCard>
                      <CardContent>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                          <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
                            {ticket.car}
                          </Typography>
                          <Typography 
                            variant="body2" 
                            sx={{ 
                              fontWeight: 600,
                              color: ticket.status === 'won' ? 'success.main' : 'text.secondary'
                            }}
                          >
                            {ticket.result}
                          </Typography>
                        </Box>
                        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <Typography variant="body2" color="text.secondary">
                            Билет {ticket.ticketNumber}
                          </Typography>
                          <Typography variant="body2" color="text.secondary">
                            {ticket.drawDate}
                          </Typography>
                        </Box>
                      </CardContent>
                    </StatsCard>
                  </motion.div>
                </Grid>
              ))}
            </Grid>
          </TabPanel>
          
          <TabPanel value={tabValue} index={2}>
            <Paper sx={{ p: 3, borderRadius: 3 }} elevation={0}>
              <Typography variant="h6" sx={{ mb: 3, fontWeight: 600 }}>Личная информация</Typography>
              <Grid container spacing={3}>
                <Grid size={{ xs: 12, sm: 6 }}>
                  <Typography variant="body2" color="text.secondary">Полное имя</Typography>
                  <Typography variant="body1" sx={{ mb: 2 }}>{profile.displayName || 'Пользователь'}</Typography>
                </Grid>
                <Grid size={{ xs: 12, sm: 6 }}>
                  <Typography variant="body2" color="text.secondary">Email</Typography>
                  <Typography variant="body1" sx={{ mb: 2 }}>aleksander@example.com</Typography>
                </Grid>
                <Grid size={{ xs: 12, sm: 6 }}>
                  <Typography variant="body2" color="text.secondary">Телефон</Typography>
                  <Typography variant="body1" sx={{ mb: 2 }}>+7 (900) 123-45-67</Typography>
                </Grid>
                <Grid size={{ xs: 12 }}>
                  <Button 
                    variant="outlined" 
                    color="primary"
                    startIcon={<Edit />}
                    sx={{ mt: 2, borderRadius: 2 }}
                  >
                    Изменить данные
                  </Button>
                </Grid>
              </Grid>
            </Paper>
          </TabPanel>
        </Box>
      </motion.div>
      <Button variant="outlined" onClick={refreshProfile} sx={{ mt: 2, borderRadius: 2 }}>Обновить профиль</Button>
    </Box>
  );
};

export default ProfilePage;
